module accu(
    input clk,
    input rst_n,
    input [7:0] data_in,
    input valid_in,
    output reg valid_out,
    output reg [9:0] data_out
);

parameter IDLE = 2'b00;
parameter INPUT = 2'b01;
parameter OUTPUT = 2'b10;

reg [1:0] state, next_state;
reg [1:0] count;
reg [9:0] accumulator;

always @(posedge clk or negedge rst_n) begin
    if (!rst_n) begin
        state <= IDLE;
        count <= 0;
        accumulator <= 0;
        valid_out <= 0;
    end else begin
        state <= next_state;
        if (state == INPUT && valid_in) begin
            accumulator <= accumulator + data_in;
            count <= count + 1;
        end else if (state == OUTPUT) begin
            valid_out <= 0;
            count <= 0;
            accumulator <= 0;
        end
    end
end

always @(*) begin
    case (state)
        IDLE: begin
            if (valid_in) begin
                next_state = INPUT;
            end else begin
                next_state = IDLE;
            end
        end
        INPUT: begin
            if (count == 2'd3) begin
                next_state = OUTPUT;
            end else if (valid_in) begin
                next_state = INPUT;
            end else begin
                next_state = IDLE;
            end
        end
        OUTPUT: begin
            next_state = IDLE;
        end
        default: begin
            next_state = IDLE;
        end
    endcase
end

always @(*) begin
    if (state == OUTPUT) begin
        data_out = accumulator;
    end else begin
        data_out = 10'b0;
    end
end

endmodule
